package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import java.util.LinkedHashSet;
import java.util.Objects;
import java.util.Set;

/**
 * Canonical logical output evidence shared by equivalent physical expressions in one memo group and input context.
 * Implementation work is deliberately excluded: equivalent operators may have different local CPU, I/O and memory costs
 * even though they describe the same logical output under the same input context. Cardinality and binding facts are
 * selected atomically so a parent never observes rows from one derivation and finite/sketch evidence from another.
 */
record LogicalOutputEstimate(CostVector evidence, BindingProfile bindingProfile) {

	LogicalOutputEstimate {
		Objects.requireNonNull(evidence, "evidence");
		evidence = outputOnly(evidence);
		bindingProfile = bindingProfile == null ? BindingProfile.ANY : bindingProfile.statisticalFacts();
	}

	static LogicalOutputEstimate from(CostVector cost) {
		return from(cost, BindingProfile.ANY);
	}

	static LogicalOutputEstimate from(CostVector cost, BindingProfile bindingProfile) {
		return new LogicalOutputEstimate(cost == null ? CostVector.INFINITE : cost, bindingProfile);
	}

	LogicalOutputEstimate stronger(LogicalOutputEstimate other) {
		if (other == null) {
			return this;
		}
		int comparison = compareEvidenceQuality(evidence, other.evidence);
		if (comparison == 0) {
			comparison = compareBindingEvidence(bindingProfile, other.bindingProfile);
		}
		if (comparison == 0) {
			// Equal-quality conflicting estimates converge conservatively and independently of discovery order.
			comparison = Double.compare(evidence.rows(), other.evidence.rows());
		}
		return comparison >= 0 ? this : other;
	}

	CostVector applyTo(CostVector cost) {
		return (cost == null ? CostVector.ZERO : cost).withOutputEstimate(evidence);
	}

	PhysicalProperties applyTo(PhysicalProperties properties) {
		PhysicalProperties safe = properties == null ? PhysicalProperties.ANY : properties;
		BindingProfile canonical = bindingProfile.mergedWith(safe.bindingProfile().executionContract());
		return safe.withBindingProfile(canonical);
	}

	private static CostVector outputOnly(CostVector cost) {
		return new CostVector(cost.rows(), 0.0d, 0.0d, 0.0d, 0.0d,
				cost.rowQErrorMean(), cost.rowQErrorMax(), 1.0d, 1.0d,
				cost.uncertaintyRows(), cost.confidence(), cost.evidenceCount());
	}

	private static int compareEvidenceQuality(CostVector left, CostVector right) {
		int comparison = Boolean.compare(exact(left), exact(right));
		if (comparison != 0) {
			return comparison;
		}
		comparison = Boolean.compare(hasDirectEvidence(left), hasDirectEvidence(right));
		if (comparison != 0) {
			return comparison;
		}
		comparison = Double.compare(left.confidence(), right.confidence());
		if (comparison != 0) {
			return comparison;
		}
		comparison = -Double.compare(left.rowQErrorMax(), right.rowQErrorMax());
		if (comparison != 0) {
			return comparison;
		}
		comparison = -Double.compare(relativeUncertainty(left), relativeUncertainty(right));
		if (comparison != 0) {
			return comparison;
		}
		comparison = Double.compare(left.evidenceCount(), right.evidenceCount());
		if (comparison != 0) {
			return comparison;
		}
		comparison = -Double.compare(left.rowQErrorMean(), right.rowQErrorMean());
		return comparison;
	}

	private static int compareBindingEvidence(BindingProfile left, BindingProfile right) {
		boolean leftContainsRight = left.satisfies(right);
		boolean rightContainsLeft = right.satisfies(left);
		return leftContainsRight == rightContainsLeft ? 0 : Boolean.compare(leftContainsRight, rightContainsLeft);
	}

	private static boolean exact(CostVector cost) {
		return cost.rowQErrorMax() == 1.0d
				&& cost.uncertaintyRows() == 0.0d
				&& cost.confidence() == 1.0d;
	}

	private static boolean hasDirectEvidence(CostVector cost) {
		return cost.evidenceCount() > 0.0d;
	}

	private static double relativeUncertainty(CostVector cost) {
		if (cost.rows() > 0.0d) {
			return cost.uncertaintyRows() / cost.rows();
		}
		return exact(cost) ? 0.0d : Double.POSITIVE_INFINITY;
	}
}

record LogicalOutputEstimateKey(Set<String> inputBindings, String observerScope,
		InputBindingContext inputBindingContext, long statisticsEpoch) {

	LogicalOutputEstimateKey {
		inputBindings = inputBindings == null || inputBindings.isEmpty() ? Set.of() : Set.copyOf(inputBindings);
		observerScope = observerScope == null || observerScope.isBlank()
				? OptimizationGoal.BAG_SEMANTICS
				: observerScope;
		inputBindingContext = inputBindingContext == null ? InputBindingContext.NONE : inputBindingContext;
		statisticsEpoch = Math.max(0L, statisticsEpoch);
	}

	static LogicalOutputEstimateKey of(OptimizationGoal goal, long statisticsEpoch) {
		OptimizationGoal safeGoal = goal == null ? OptimizationGoal.root() : goal;
		Set<String> inputBindings = new LinkedHashSet<>(safeGoal.requiredProperties().boundVars());
		inputBindings.addAll(safeGoal.requiredProperties().inputBoundVars());
		inputBindings.addAll(safeGoal.inputBindingContext().assuredBindingNames());
		return new LogicalOutputEstimateKey(inputBindings, safeGoal.semanticScope(), safeGoal.inputBindingContext(),
				statisticsEpoch);
	}

	boolean matches(WinnerKey winnerKey) {
		if (winnerKey == null
				|| !observerScope.equals(winnerKey.semanticScope())
				|| !inputBindingContext.equals(winnerKey.inputBindingContext())) {
			return false;
		}
		Set<String> winnerInputs = new LinkedHashSet<>(winnerKey.requiredProperties().boundVars());
		winnerInputs.addAll(winnerKey.requiredProperties().inputBoundVars());
		winnerInputs.addAll(winnerKey.inputBindingContext().assuredBindingNames());
		return inputBindings.equals(winnerInputs);
	}
}

/**
 * Identifies the logical population selected by one physical expression without treating its cardinality estimate as
 * part of that identity. The memo group and complete logical goal establish equivalence; selected output names retain
 * intentionally narrower physical surfaces while binding evidence remains a refinable value rather than a key.
 */
record SelectedLogicalOutputEstimateKey(LogicalOutputEstimateKey logicalGoal, Set<String> selectedOutputNames) {

	SelectedLogicalOutputEstimateKey {
		Objects.requireNonNull(logicalGoal, "logicalGoal");
		selectedOutputNames = selectedOutputNames == null || selectedOutputNames.isEmpty()
				? Set.of()
				: Set.copyOf(selectedOutputNames);
	}

	static SelectedLogicalOutputEstimateKey of(OptimizationGoal goal, long statisticsEpoch,
			Set<String> selectedOutputNames) {
		Set<String> names = selectedOutputNames == null || selectedOutputNames.isEmpty()
				? Set.of()
				: Set.copyOf(selectedOutputNames);
		return new SelectedLogicalOutputEstimateKey(LogicalOutputEstimateKey.of(goal, statisticsEpoch), names);
	}

	boolean matches(WinnerKey winnerKey, Winner winner) {
		return logicalGoal.matches(winnerKey)
				&& winner != null
				&& winner.selectedOutputExplicit()
				&& selectedOutputNames.equals(winner.selectedOutputNames());
	}
}
